<script>		function validateForm() {			var check = true;			var error = '<div class="alert"><button type="button" class="close" data-dismiss="alert">&times;</button><strong>ERROR!</strong><br />';			// check apakah tanggal sudah terisi			if ($("#tgl1").val()=='') {				check = false;				error += 'Anda harus mengisi tanggal awal laporan<br/>';			}			if ($("#tgl2").val()=='') {				check = false;				error += 'Anda harus mengisi tanggal akhir laporan<br/>';			}			if ($("#usero").val()=='') {				check = false;				error += 'Anda harus mengisi mekanik<br/>';			}			error += '</div>';			if (check == false) $("#error-area").html(error);			else generate_laporan();		}				function generate_laporan() {				$.get("<?php echo base_url("laporan"); ?>/laporan_penggajian_ajax/"+$('#tgl1').val()+"/"+$('#tgl2').val()+"/"+$('#usero').val(), function(data) {					$("#toro-area").html(data);				});		}		$(function() {			$("#tgl1").datepicker({				dateFormat : "yy-mm-dd",				showButtonPanel : true			});			$("#tgl2").datepicker({				dateFormat : "yy-mm-dd",				showButtonPanel : true			});		});	</script>